// validAPIKeys would be loaded from a secure store in production.
var validAPIKeys = map[string]bool{
	"dev-api-key-12345": true,
}

func authUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	// Allow reflection RPCs without auth in dev mode only
	if isDevEnvironment() && strings.HasPrefix(info.FullMethod, "/grpc.reflection.") {
		return handler(ctx, req)
	}

	// Allow health checks without auth
	if strings.HasPrefix(info.FullMethod, "/grpc.health.") {
		return handler(ctx, req)
	}

	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Errorf(codes.Unauthenticated, "missing metadata")
	}

	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return nil, status.Errorf(codes.Unauthenticated, "missing authorization header")
	}

	token := strings.TrimPrefix(authHeaders[0], "Bearer ")
	if !validAPIKeys[token] {
		return nil, status.Errorf(codes.Unauthenticated, "invalid API key")
	}

	return handler(ctx, req)
}

func authStreamInterceptor(
	srv interface{},
	ss grpc.ServerStream,
	info *grpc.StreamServerInfo,
	handler grpc.StreamHandler,
) error {
	// Allow reflection streams in dev mode only
	if isDevEnvironment() && strings.HasPrefix(info.FullMethod, "/grpc.reflection.") {
		return handler(srv, ss)
	}

	md, ok := metadata.FromIncomingContext(ss.Context())
	if !ok {
		return status.Errorf(codes.Unauthenticated, "missing metadata")
	}

	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return status.Errorf(codes.Unauthenticated, "missing authorization header")
	}

	token := strings.TrimPrefix(authHeaders[0], "Bearer ")
	if !validAPIKeys[token] {
		return status.Errorf(codes.Unauthenticated, "invalid API key")
	}

	return handler(srv, ss)
}

